// Получаем входящие данные
const items = $input.all();

// Обрабатываем каждый элемент
const result = items.map(item => {
  // Берем содержимое поля message (это строка!)
  const messageString = item.json.message;

  try {
    // Парсим строку в настоящий JSON
    const parsedMessage = JSON.parse(messageString);

    // Возвращаем объединенный результат
    // Берем все поля из исходного сообщения + распарсенные поля из message
    return {
      ...item.json,        // тут будет topic и исходное message
      ...parsedMessage,    // а тут title, summary, news_link
      parsed: true         // метка, что мы обработали
    };
  } catch (error) {
    // Если парсинг не удался, возвращаем как есть и добавляем ошибку
    return {
      ...item.json,
      error: `Failed to parse message: ${error.message}`
    };
  }
});

// Возвращаем результат
return result;

const item = $input.first().json;

const title = item.title || 'Без заголовка';
const summary = item.summary || 'Нет описания';
const newsLink = item.news_link;

// HTML-версия ссылки
const linkText = newsLink 
  ? `\n\n🔗 <a href="${newsLink}">Читать полностью</a>` 
  : '\n\n❌ Ссылка отсутствует';

// Собираем пост в HTML-формате
// **жирный** меняем на <b>жирный</b>
const post = `<b>${title}</b>\n\n${summary}${linkText}\n\n@english_lessons_with_news`;

return [{
  json: {
    formattedPost: post,
    hasLink: !!newsLink,
    // Добавляем метку, что формат HTML (для отладки)
    format: 'html',
    ...item
  },
  binary: $input.first().binary
}];

const item = $input.first().json;
const rawText = item.text || item.response || JSON.stringify(item);

console.log('📥 Сырой ответ от LLM (первые 200 символов):', rawText.substring(0, 200));

try {
  let quizData;

  // Вариант 1: Если это уже объект
  if (typeof rawText === 'object') {
    quizData = rawText;
  }
  // Вариант 2: Пробуем распарсить как есть
  else {
    try {
      quizData = JSON.parse(rawText);
    } catch (e) {
      // Вариант 3: Убираем Markdown-блоки
      const cleanedText = rawText
        .replace(/```json\s*/g, '')
        .replace(/```\s*$/g, '')
        .replace(/`/g, '')
        .trim();

      console.log('🧹 Очищенный текст:', cleanedText.substring(0, 200));
      quizData = JSON.parse(cleanedText);
    }
  }

  // Извлекаем викторину (может быть в корне или в поле quiz)
  const quiz = quizData.quiz || quizData;

  // Базовая проверка структуры
  if (!quiz.question || !Array.isArray(quiz.options) || !quiz.explanation) {
    throw new Error('Неполная структура викторины');
  }

  console.log('✅ Парсинг успешен:', {
    question: quiz.question.substring(0, 50) + '...',
    options: quiz.options.length,
    explanation: quiz.explanation.length
  });

  // Возвращаем чистый JSON с викториной
  return [{
    json: {
      quiz: quiz,  // сохраняем как есть
      parsed: true,
      timestamp: new Date().toISOString()
    }
  }];

} catch (error) {
  console.error('❌ Ошибка парсинга:', error.message);

  // Возвращаем ошибку, но не ломаем пайплайн
  return [{
    json: {
      error: error.message,
      raw: rawText.substring(0, 500),
      parsed: false
    }
  }];
}

const input = $input.first().json;

// Проверяем, был ли успешный парсинг
if (!input.quiz && !input.parsed) {
  console.error('❌ Нет данных викторины, используем запасной вариант');
  return [/* запасной вариант */];
}

const quiz = input.quiz;

// Сохраняем правильный ответ (предполагаем, что он под индексом 0)
const correctAnswerText = quiz.options[0];

// Перемешиваем массив options (алгоритм Фишера-Йетса)
const shuffledOptions = [...quiz.options];
for (let i = shuffledOptions.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [shuffledOptions[i], shuffledOptions[j]] = [shuffledOptions[j], shuffledOptions[i]];
}

// Находим новый индекс правильного ответа
const correctIndex = shuffledOptions.indexOf(correctAnswerText);

// Подготовка данных с проверкой лимитов Telegram
let question = quiz.question;
let options = shuffledOptions.map(opt => {
  if (opt.length > 100) {
    console.warn(`⚠️ Вариант слишком длинный (${opt.length}), обрезаем`);
    return opt.substring(0, 97) + '...';
  }
  return opt;
});
let explanation = quiz.explanation || 'Правильный ответ указан выше.';

// Проверка длины вопроса (макс 300)
if (question.length > 300) {
  question = question.substring(0, 297) + '...';
}

// Проверка длины объяснения (макс 200)
if (explanation.length > 200) {
  explanation = explanation.substring(0, 197) + '...';
}

// Проверка количества вариантов
if (options.length < 2) {
  while (options.length < 2) options.push('Option ' + (options.length + 1));
} else if (options.length > 10) {
  options = options.slice(0, 10);
  // Корректируем correctIndex, если правильный ответ оказался за пределами
  if (correctIndex >= options.length) {
    // В крайнем случае ставим 0, но такого не должно быть
    correctIndex = 0;
  }
}

console.log('🎲 Викторина перемешана. Правильный ответ теперь на позиции:', correctIndex);

return [{
  json: {
    chat_id: "@english_lessons_with_news",  // замени на свой
    question: question,
    options: options,
    type: "quiz",
    correct_option_id: correctIndex,
    explanation: explanation,
    is_anonymous: true
  }
}];
